import{a as e,c as t,d as n,f as r,u as i,w as a,x as o,y as s}from"./runtime-core.esm-bundler-CD3o_SA6.js";import{t as c}from"./_plugin-vue_export-helper-B80Cc4Ui.js";var l={},u={class:`chapter-header`},d={class:`breadcrumb`},f={class:`page-container`},p={class:`chapter-nav`};function m(c,l){let m=o(`router-link`);return s(),t(`div`,null,[e(`header`,u,[e(`div`,d,[r(m,{to:`/`},{default:a(()=>[...l[0]||=[n(`Study Guide`,-1)]]),_:1}),l[3]||=n(` › `,-1),r(m,{to:`/sa`},{default:a(()=>[...l[1]||=[n(`SA`,-1)]]),_:1}),l[4]||=n(` › `,-1),r(m,{to:`/sa/fundamentals`},{default:a(()=>[...l[2]||=[n(`Fundamentals`,-1)]]),_:1}),l[5]||=n(` › Chapter 4 `,-1)]),l[6]||=i(`<h1>Chapter 4: Architectural Characteristics Defined</h1><p class="chapter-desc">The &quot;-ilities&quot; that define what a system must be capable of — independent of the problem domain. How to identify, categorize, and reason about them.</p><div class="stats-bar"><span class="stat-badge">3 Definition Criteria</span><span class="stat-badge">4 Categories</span><span class="stat-badge">20+ Named Characteristics</span><span class="stat-badge">Least Worst Architecture</span></div>`,3)]),e(`div`,f,[l[9]||=i(`<div class="toc"><h2>Table of Contents</h2><ol><li><a href="#s4-1">Architectural Characteristics and System Design</a></li><li><a href="#s4-2">What makes something an architectural characteristic?</a></li><li><a href="#s4-3">Operational Characteristics</a></li><li><a href="#s4-4">Structural Characteristics</a></li><li><a href="#s4-5">Cloud Characteristics</a></li><li><a href="#s4-6">Cross-Cutting Characteristics</a></li><li><a href="#s4-7">Trade-Offs and Least Worst Architecture</a></li><li><a href="#takeaways">Key Takeaways</a></li></ol></div><h2 class="section-title" id="s4-1">Architectural Characteristics and System Design</h2><div class="content-section"><p>A software solution consists of two distinct types of requirements:</p><table class="comparison-table"><thead><tr><th>Type</th><th>What it answers</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Domain requirements (functional)</strong></td><td>What the system should <em>do</em></td><td>Process an order, send an invoice, display a map, authenticate a user</td></tr><tr><td><strong>Architectural characteristics (&quot;-ilities&quot;)</strong></td><td>What the system should <em>be capable of</em></td><td>Handle 10,000 concurrent users, recover from failure in under 30 seconds, be deployed in EU only</td></tr></tbody></table><div class="info-box note-box"><p><strong>Why &quot;architectural characteristics&quot; instead of &quot;non-functional requirements&quot;?</strong> The term &quot;non-functional&quot; is self-denigrating — it implies these are less important. &quot;Architectural characteristics&quot; better captures that they are <em>critical</em> to the system&#39;s success. In Head First Software Architecture they&#39;re called &quot;capabilities&quot; — the system&#39;s behavior is domain, its capabilities are architectural characteristics.</p></div></div><h2 class="section-title" id="s4-2">What makes something an architectural characteristic?</h2><div class="content-section"><p>To qualify as an architectural characteristic, a requirement must satisfy <strong>three criteria</strong>:</p><table class="comparison-table"><thead><tr><th>Criterion</th><th>Meaning</th><th>Example</th></tr></thead><tbody><tr><td><strong>1. Specifies a nondomain design consideration</strong></td><td>It&#39;s about <em>how</em> to implement requirements, not <em>what</em> to implement. The &quot;why&quot; and the operational criteria.</td><td>Performance is often important but doesn&#39;t appear in functional specs. &quot;Prevent technical debt&quot; never appears in a requirements doc but is always a concern.</td></tr><tr><td><strong>2. Influences structural aspect of the design</strong></td><td>It requires <em>structural</em> design decisions — not just good coding practices.</td><td>Security can be achieved via code hygiene (design) in a monolith, but requires architectural structure (hardened service, strict access) in a distributed system.</td></tr><tr><td><strong>3. Critical or important to application success</strong></td><td>It&#39;s not just a &quot;nice to have&quot; — the system fails to meet its goals without it.</td><td>Scalability beyond 10,000 users requires a distributed architecture. No clever code design will substitute for structural change.</td></tr></tbody></table><h4 class="subsubsection-title">Implicit vs Explicit Characteristics</h4><table class="comparison-table"><thead><tr><th>Type</th><th>Definition</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Implicit</strong></td><td>Rarely appear in requirements, but necessary for success. Architects must discover these from domain knowledge.</td><td>Availability, reliability, security — virtually all applications need these even if never specified.</td></tr><tr><td><strong>Explicit</strong></td><td>Appear directly in requirements documents or client specifications.</td><td>&quot;The system must support 99.99% uptime,&quot; &quot;All data must be stored in the EU&quot;</td></tr></tbody></table></div><h2 class="section-title" id="s4-3">Operational Architectural Characteristics</h2><div class="content-section"><p>These overlap heavily with DevOps concerns and cover capabilities like performance, scalability, and reliability.</p><table class="comparison-table"><thead><tr><th>Characteristic</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Availability</strong></td><td>How much of the time the system must be available (99.9%, 99.99%, etc.). Drives redundancy, failover, health checks.</td></tr><tr><td><strong>Continuity</strong></td><td>Disaster recovery capability. How does the system survive a data center failure?</td></tr><tr><td><strong>Performance</strong></td><td>Response times, throughput, peak load handling. Measured via stress testing, peak analysis.</td></tr><tr><td><strong>Recoverability</strong></td><td>How quickly the system comes back after a disaster. RTO (Recovery Time Objective) and RPO (Recovery Point Objective). Drives backup strategies.</td></tr><tr><td><strong>Reliability/Safety</strong></td><td>Whether system failures cost lives or large sums of money. Mission-critical systems. Spectrum, not binary.</td></tr><tr><td><strong>Robustness</strong></td><td>Handling error and boundary conditions while running — network loss, power failure, malformed input.</td></tr><tr><td><strong>Scalability</strong></td><td>Ability to perform and operate as load increases. Both vertical (bigger machines) and horizontal (more machines).</td></tr></tbody></table></div><h2 class="section-title" id="s4-4">Structural Architectural Characteristics</h2><div class="content-section"><p>About code quality and internal structure. Architects often share responsibility for these with developers.</p><table class="comparison-table"><thead><tr><th>Characteristic</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Configurability</strong></td><td>How easily users or operators can change system configuration without modifying code.</td></tr><tr><td><strong>Extensibility</strong></td><td>How well the architecture can accommodate new functionality without major structural changes.</td></tr><tr><td><strong>Installability</strong></td><td>Ease of deploying the system on all required platforms.</td></tr><tr><td><strong>Leverageability/Reuse</strong></td><td>Extent to which common components can be reused across multiple products or services.</td></tr><tr><td><strong>Maintainability</strong></td><td>How easy it is to apply changes and enhancements. Correlates with coupling, cohesion, and cyclomatic complexity.</td></tr><tr><td><strong>Portability</strong></td><td>Ability to run on multiple platforms (Oracle DB vs MySQL, Windows vs Linux).</td></tr><tr><td><strong>Upgradeability</strong></td><td>How easily the system can be upgraded to new versions without downtime or data loss.</td></tr></tbody></table></div><h2 class="section-title" id="s4-5">Cloud Architectural Characteristics</h2><div class="content-section"><p>New in the 2nd edition — the cloud has become pervasive enough to warrant its own category of architectural characteristics:</p><table class="comparison-table"><thead><tr><th>Characteristic</th><th>Definition</th></tr></thead><tbody><tr><td><strong>On-demand Scalability</strong></td><td>Cloud provider scales up resources dynamically based on demand. No need to provision for peak capacity upfront.</td></tr><tr><td><strong>On-demand Elasticity</strong></td><td>Flexible resource allocation as demand spikes and subsides. Similar to scalability but emphasizes the ability to scale <em>down</em> as well.</td></tr><tr><td><strong>Zone-based Availability</strong></td><td>Separating resources by computing zones for resilience. Failure of one zone doesn&#39;t impact others.</td></tr><tr><td><strong>Region-based Privacy &amp; Security</strong></td><td>Legal constraints on where data can be stored. GDPR requires EU citizen data to stay in the EU. Architecture must respect data residency laws.</td></tr></tbody></table></div><h2 class="section-title" id="s4-6">Cross-Cutting Architectural Characteristics</h2><div class="content-section"><p>Characteristics that don&#39;t fit neatly into operational or structural categories but form important design constraints:</p><table class="comparison-table"><thead><tr><th>Characteristic</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Accessibility</strong></td><td>Support for users with disabilities (colorblindness, hearing loss). WCAG compliance.</td></tr><tr><td><strong>Archivability</strong></td><td>Rules for archiving or deleting data after a specified period. Important for compliance and storage cost.</td></tr><tr><td><strong>Authentication</strong></td><td>Ensuring users are who they say they are (login, MFA, SSO).</td></tr><tr><td><strong>Authorization</strong></td><td>Ensuring users can access only what they&#39;re allowed to (RBAC, ABAC, ACLs).</td></tr><tr><td><strong>Legal</strong></td><td>Legislative constraints: GDPR, Sarbanes-Oxley, PCI-DSS, HIPAA. Architecture must comply with applicable regulations.</td></tr><tr><td><strong>Privacy</strong></td><td>Ability to hide transactions even from internal employees (DBAs, network admins). Encryption, key management.</td></tr><tr><td><strong>Security</strong></td><td>Encryption in transit and at rest, authentication, authorization, penetration testing. A broad cross-cutting concern.</td></tr><tr><td><strong>Supportability</strong></td><td>Level of logging, monitoring, alerting, and tooling needed for operators to diagnose and fix problems.</td></tr><tr><td><strong>Usability</strong></td><td>How easily users can achieve their goals. Training time required, UX patterns, accessibility.</td></tr></tbody></table><div class="info-box note-box"><p><strong>Ambiguity warning:</strong> Many of these terms overlap or are defined differently by different organizations. <em>Interoperability</em> implies published APIs and ease of integration; <em>compatibility</em> implies adherence to industry standards. <em>Availability</em> and <em>reliability</em> are related but distinct — IP is available but not reliable (packets can be lost). Build a shared ubiquitous language within your organization.</p></div></div><h2 class="section-title" id="s4-7">Trade-Offs and Least Worst Architecture</h2><div class="content-section"><p>Architectural characteristics are deeply synergistic — changing one almost always affects others:</p><table class="comparison-table"><thead><tr><th>Improve this</th><th>Often degrades this</th><th>Reason</th></tr></thead><tbody><tr><td>Security</td><td>Performance</td><td>Encryption, indirection, and additional authentication steps add processing overhead</td></tr><tr><td>Scalability</td><td>Simplicity, cost</td><td>Distributed systems require more infrastructure, more complexity, more failure points</td></tr><tr><td>Availability</td><td>Cost, consistency</td><td>Redundant systems cost money; CAP theorem means you can&#39;t have both full consistency and availability in distributed systems</td></tr><tr><td>Testability</td><td>Performance</td><td>More abstraction layers (for testability) add overhead</td></tr></tbody></table><div class="info-box key-point-box"><p><strong>&quot;Never strive for the best architecture; aim for the least worst architecture.&quot;</strong><br> Systems that try to support too many architectural characteristics become generic solutions that attempt to solve every business problem. They quickly become unwieldy and rarely work.<br><br> The ideal architecture is one that is <strong>as iterative as possible</strong> — easy to change as understanding improves. This is the architecture equivalent of Agile development.</p></div><div class="info-box analogy-box"><p><strong>Helicopter analogy:</strong> Helicopter controls are synergistic — changing throttle affects pitch, which affects direction. Flying is a constant balancing act. Architectural characteristics work the same way. A skilled architect learns to balance them, making small adjustments rather than trying to get everything perfect in one go.</p></div><p>The goal: support only the characteristics that are <em>critical or important to success</em>. Each additional supported characteristic adds design complexity. Choose the fewest possible architectural characteristics rather than the most.</p></div><div class="takeaways" id="takeaways"><h3>Key Takeaways — Chapter 4</h3><ul><li>Architectural characteristics (the &quot;-ilities&quot;) define <em>what a system must be capable of</em>, independent of what it does.</li><li>A requirement is an architectural characteristic if it: specifies a nondomain design consideration, influences structural design, AND is critical to success.</li><li><strong>Implicit characteristics</strong> (availability, security, reliability) are never written in specs but are always needed. Architects must identify them from domain knowledge.</li><li>Four categories: <strong>operational</strong> (performance, scalability, availability), <strong>structural</strong> (maintainability, extensibility), <strong>cloud</strong> (elasticity, data residency), and <strong>cross-cutting</strong> (security, legal, usability).</li><li>Characteristics are deeply synergistic — improving one often degrades another. This is why architecture is about trade-offs, not optimization.</li><li>The goal is the <strong>least worst architecture</strong> — one that balances the critical characteristics without trying to maximize everything, and that is easy to iterate on.</li><li>Each organization should define its own ubiquitous language for characteristics — industry standard definitions are inconsistent and overlapping.</li></ul></div>`,16),e(`div`,p,[r(m,{to:`/sa/fundamentals/ch3`,class:`prev`},{default:a(()=>[...l[7]||=[n(`← Chapter 3`,-1)]]),_:1}),r(m,{to:`/sa/fundamentals/ch5`,class:`next`},{default:a(()=>[...l[8]||=[n(`Chapter 5 →`,-1)]]),_:1})])])])}var h=c(l,[[`render`,m]]);export{h as default};